const express = require('express');
const morgan = require('morgan');
const winston = require('winston');
const helmet = require('helmet');
const app = express();

// Create a Winston logger
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  transports: [
    new winston.transports.File({ filename: 'audit.log' })
  ]
});

// Middleware to validate and sanitize user input
function validateInput(req, res, next) {
  const username = req.headers['x-username'];
  const ip = req.ip;
  const customHeader = req.headers['x-custom-header'];

  if (typeof username !== 'string' || !/^[a-zA-Z0-9_]+$/.test(username)) {
    return res.status(400).send('Invalid username');
  }

  if (typeof customHeader !== 'string' || !/^[a-zA-Z0-9_]+$/.test(customHeader)) {
    return res.status(400).send('Invalid custom header');
  }

  req.validatedData = { username, ip, customHeader };
  next();
}

// Use Helmet for basic security
app.use(helmet());

// Use Morgan to log HTTP requests
app.use(morgan('combined', {
  stream: {
    write: (message) => logger.info(message.trim())
  }
}));

// Apply input validation middleware
app.use(validateInput);

// Example route
app.get('/', (req, res) => {
  const { username, ip, customHeader } = req.validatedData;
  logger.info('User accessed root', { username, ip, customHeader });
  res.send('Hello, secure world!');
});

// Start the server
app.listen(3000, () => {
  console.log('Server is running on port 3000');
});